"""
Train CostVolumeDepthNet: Cost-volume based light field depth estimation.

Training:
  - Domain-balanced sampling (equal Urban / Lambertian / Non-Lambertian per epoch)
  - L1Loss (MAE)
  - Adam lr=1e-4, ReduceLROnPlateau
  - 10 epochs pilot, batch_size=2, 128x128
  - Per-domain val MAE logged after each epoch
  - LR halving if loss increases for 3+ consecutive steps at start
"""

import argparse
import json
import logging
import os
import sys
import time
from collections import defaultdict

import numpy as np
import torch
import torch.nn.functional as F
from torch.optim import Adam
from torch.optim.lr_scheduler import ReduceLROnPlateau
from torch.utils.data import DataLoader, WeightedRandomSampler

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from datasets.unified_lf_dataset import UnifiedLFDataset
from models.cost_volume_net import CostVolumeDepthNet

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    datefmt="%H:%M:%S",
)
logger = logging.getLogger(__name__)


def build_balanced_sampler(dataset):
    """Build WeightedRandomSampler that balances across domain groups."""
    groups = [dataset.scenes[i].get("group", "Unknown") for i in range(len(dataset))]
    unique_groups = sorted(set(groups))
    group_counts = {g: groups.count(g) for g in unique_groups}

    # Weight = 1/count so rare groups are sampled more often
    weights = [1.0 / group_counts[g] for g in groups]
    sampler = WeightedRandomSampler(
        weights=weights, num_samples=len(dataset), replacement=True
    )
    logger.info(
        f"Balanced sampler: {group_counts} -> effective equal sampling per group"
    )
    return sampler


def train_one_epoch(model, loader, optimizer, device, epoch, lr_patience):
    """Train one epoch. Returns (avg_loss, step_losses)."""
    model.train()
    total_loss = 0.0
    consecutive_increases = 0
    prev_loss = None

    for batch_idx, batch in enumerate(loader):
        views = batch["views"].to(device)  # (B, 81, 3, H, W)
        gt = batch["gt"].to(device)        # (B, 1, H, W)

        pred = model(views)
        loss = F.l1_loss(pred, gt)

        optimizer.zero_grad()
        loss.backward()
        torch.nn.utils.clip_grad_norm_(model.parameters(), 5.0)
        optimizer.step()

        raw_loss = loss.item()
        total_loss += raw_loss

        # LR halving if loss increases for 3+ consecutive steps early in training
        if epoch == 1 and prev_loss is not None:
            if raw_loss > prev_loss:
                consecutive_increases += 1
                if consecutive_increases >= 3:
                    old_lr = optimizer.param_groups[0]["lr"]
                    new_lr = old_lr * 0.5
                    optimizer.param_groups[0]["lr"] = new_lr
                    logger.warning(
                        f"  Loss increased {consecutive_increases}x -> "
                        f"LR halved: {old_lr:.2e} -> {new_lr:.2e}"
                    )
                    consecutive_increases = 0
                    prev_loss = None
                    continue
            else:
                consecutive_increases = 0
        prev_loss = raw_loss

        if (batch_idx + 1) % 10 == 0:
            logger.info(
                f"  Epoch {epoch} step {batch_idx + 1}/{len(loader)} "
                f"loss={raw_loss:.6f} lr={optimizer.param_groups[0]['lr']:.2e}"
            )

    avg_loss = total_loss / max(len(loader), 1)
    return avg_loss


@torch.no_grad()
def validate(model, loader, device):
    """Validate model and compute per-group MAE."""
    model.eval()
    per_group_errors = defaultdict(list)

    for batch in loader:
        views = batch["views"].to(device)
        gt = batch["gt"].to(device)
        groups = batch["group"]

        pred = model(views)

        pred_np = pred.cpu().numpy()
        gt_np = gt.cpu().numpy()

        for i in range(pred_np.shape[0]):
            mae = float(np.abs(pred_np[i] - gt_np[i]).mean())
            grp = groups[i] if i < len(groups) else "Unknown"
            per_group_errors[grp].append(mae)

    metrics = {}
    all_errors = []
    for group, errors in sorted(per_group_errors.items()):
        mean_mae = float(np.mean(errors))
        metrics[f"MAE_{group}"] = mean_mae
        all_errors.extend(errors)
        logger.info(f"  {group}: MAE={mean_mae:.6f} ({len(errors)} samples)")

    metrics["MAE_overall"] = (
        float(np.mean(all_errors)) if all_errors else float("inf")
    )
    return metrics


def main():
    parser = argparse.ArgumentParser(description="Train CostVolumeDepthNet")
    parser.add_argument("--epochs", type=int, default=10)
    parser.add_argument("--batch_size", type=int, default=2)
    parser.add_argument("--lr", type=float, default=1e-4)
    parser.add_argument("--weight_decay", type=float, default=1e-5)
    parser.add_argument("--target_size", type=int, nargs=2, default=[128, 128])
    parser.add_argument("--num_workers", type=int, default=4)
    parser.add_argument("--output_dir", type=str, default="outputs/exp_cost_volume")
    parser.add_argument("--seed", type=int, default=42)
    args = parser.parse_args()

    # Reproducibility
    torch.manual_seed(args.seed)
    np.random.seed(args.seed)

    os.makedirs(args.output_dir, exist_ok=True)
    os.makedirs("checkpoints", exist_ok=True)

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    logger.info(f"Device: {device}")

    # Datasets — train/val split from manifest
    train_ds = UnifiedLFDataset(
        split="train",
        num_views=81,
        target_size=tuple(args.target_size),
        augment=True,
    )
    val_ds = UnifiedLFDataset(
        split="val",
        num_views=81,
        target_size=tuple(args.target_size),
        augment=False,
    )
    logger.info(f"Train: {len(train_ds)} scenes")
    logger.info(f"Val:   {len(val_ds)} scenes")

    if len(train_ds) == 0:
