    # Domain-balanced sampler
    train_sampler = build_balanced_sampler(train_ds)

    train_loader = DataLoader(
        train_ds, batch_size=args.batch_size, sampler=train_sampler,
        num_workers=args.num_workers, pin_memory=True, drop_last=True,
    )
    val_loader = DataLoader(
        val_ds, batch_size=args.batch_size, shuffle=False,
        num_workers=args.num_workers, pin_memory=True,
    )

    # Model
    model = CostVolumeDepthNet(ndisp=32, max_disp=3.0).to(device)
    params = sum(p.numel() for p in model.parameters())
    logger.info(f"Model: CostVolumeDepthNet, params={params:,}")

    optimizer = Adam(
        model.parameters(), lr=args.lr, weight_decay=args.weight_decay
    )
    scheduler = ReduceLROnPlateau(
        optimizer, mode="min", factor=0.5, patience=2, min_lr=1e-6
    )

    # Training loop
    best_overall_mae = float("inf")
    best_epoch = -1
    history = []

    for epoch in range(1, args.epochs + 1):
        logger.info(f"=== Epoch {epoch}/{args.epochs} ===")
        t0 = time.time()

        avg_loss = train_one_epoch(
            model, train_loader, optimizer, device, epoch, lr_patience=2
        )

        elapsed = time.time() - t0
        logger.info(f"  Train loss={avg_loss:.6f} ({elapsed:.1f}s)")

        val_metrics = validate(model, val_loader, device)
        overall_mae = val_metrics["MAE_overall"]
        logger.info(f"  Val MAE_overall={overall_mae:.6f}")

        scheduler.step(overall_mae)

        history.append({
            "epoch": epoch,
            "train_loss": avg_loss,
            "val_metrics": val_metrics,
            "lr": optimizer.param_groups[0]["lr"],
        })

        # Save best
        if overall_mae < best_overall_mae:
            best_overall_mae = overall_mae
            best_epoch = epoch
            torch.save({
                "epoch": epoch,
                "model_state_dict": model.state_dict(),
                "optimizer_state_dict": optimizer.state_dict(),
                "val_metrics": val_metrics,
                "overall_mae": overall_mae,
            }, os.path.join(args.output_dir, "best_model.pth"))
            logger.info(f"  * New best overall MAE={overall_mae:.6f}")

    # Final report
    logger.info("=" * 60)
    logger.info("TRAINING COMPLETE")
    logger.info(f"  Best val MAE: {best_overall_mae:.6f} at epoch {best_epoch}")
    if history:
        last = history[-1]["val_metrics"]
        for k in sorted(last.keys()):
            if k.startswith("MAE_"):
                logger.info(f"  {k} (last epoch): {last[k]:.6f}")

    # Save final checkpoint
    torch.save({
        "epoch": args.epochs,
        "model_state_dict": model.state_dict(),
        "history": history,
        "best_overall_mae": best_overall_mae,
        "best_epoch": best_epoch,
    }, os.path.join(args.output_dir, "final_model.pth"))

    with open(os.path.join(args.output_dir, "training_history.json"), "w") as f:
        json.dump({
            "config": vars(args),
            "total_params": params,
            "best_overall_mae": best_overall_mae,
            "best_epoch": best_epoch,
