Training:
  - All domains (Urban, Lambertian, Non-Lambertian)
  - SmoothL1Loss
  - 50 epochs, batch_size=4, lr=1e-3, Adam, CosineAnnealing
  - Per-domain val MAE logged after each epoch
"""

import argparse
import json
import logging
import os
import sys
import time
from collections import defaultdict

import numpy as np
import torch
import torch.nn.functional as F
from torch.optim import Adam
from torch.optim.lr_scheduler import CosineAnnealingLR
from torch.utils.data import DataLoader

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from datasets.unified_lf_dataset import UnifiedLFDataset
from models.angular_freq_net_v2 import AngularFreqNetV2

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    datefmt="%H:%M:%S",
)
logger = logging.getLogger(__name__)


def train_one_epoch(model, loader, optimizer, device, epoch):
    """Train one epoch. Returns (avg_loss, step_losses)."""
    model.train()
    total_loss = 0.0

    for batch_idx, batch in enumerate(loader):
        views = batch["views"].to(device)    # (B, 81, 3, H, W)
        gt = batch["gt"].to(device)          # (B, 1, H, W)

        pred = model(views)
        loss = F.smooth_l1_loss(pred, gt)

        optimizer.zero_grad()
        loss.backward()
        torch.nn.utils.clip_grad_norm_(model.parameters(), 5.0)
        optimizer.step()

        raw_loss = loss.item()
        total_loss += raw_loss

        if (batch_idx + 1) % 5 == 0:
            logger.info(
                f"  Epoch {epoch} step {batch_idx + 1}/{len(loader)} "
                f"loss={raw_loss:.6f}"
            )

    avg_loss = total_loss / max(len(loader), 1)
    return avg_loss


@torch.no_grad()
def validate(model, loader, device):
    """Validate model and compute per-group MAE."""
    model.eval()
    per_group_errors = defaultdict(list)

    for batch in loader:
        views = batch["views"].to(device)
        gt = batch["gt"].to(device)
        groups = batch["group"]

        pred = model(views)

        pred_np = pred.cpu().numpy()
        gt_np = gt.cpu().numpy()

        for i in range(pred_np.shape[0]):
            mae = float(np.abs(pred_np[i] - gt_np[i]).mean())
            grp = groups[i] if i < len(groups) else "Unknown"
            per_group_errors[grp].append(mae)

    metrics = {}
    all_errors = []
    for group, errors in sorted(per_group_errors.items()):
        mean_mae = float(np.mean(errors))
        metrics[f"MAE_{group}"] = mean_mae
        all_errors.extend(errors)
        logger.info(f"  {group}: MAE={mean_mae:.6f} ({len(errors)} samples)")

    metrics["MAE_overall"] = float(np.mean(all_errors)) if all_errors else float("inf")
    return metrics


def main():
    parser = argparse.ArgumentParser(description="Train AngularFreqNet V2")
    parser.add_argument("--epochs", type=int, default=50)
    parser.add_argument("--batch_size", type=int, default=4)
    parser.add_argument("--lr", type=float, default=1e-3)
    parser.add_argument("--weight_decay", type=float, default=1e-4)
    parser.add_argument("--target_size", type=int, nargs=2, default=[128, 128])
    parser.add_argument("--num_views", type=int, default=81)
    parser.add_argument("--num_workers", type=int, default=4)
    parser.add_argument("--output_dir", type=str, default="outputs/exp_v2_unet_fft")
    parser.add_argument("--seed", type=int, default=42)
    args = parser.parse_args()

    # Reproducibility
    torch.manual_seed(args.seed)
    np.random.seed(args.seed)

    os.makedirs(args.output_dir, exist_ok=True)
    os.makedirs("checkpoints", exist_ok=True)

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    logger.info(f"Device: {device}")

    # Dataset — all domains, train/val split from manifest
    train_ds = UnifiedLFDataset(
        split="train",
        num_views=args.num_views,
        target_size=tuple(args.target_size),
        augment=True,
    )
    val_ds = UnifiedLFDataset(
        split="val",
        num_views=args.num_views,
        target_size=tuple(args.target_size),
        augment=False,
    )
    logger.info(f"Train: {len(train_ds)} scenes")
    logger.info(f"Val:   {len(val_ds)} scenes")

    if len(train_ds) == 0:
        logger.error("No training scenes found!")
        sys.exit(1)

    train_loader = DataLoader(
        train_ds, batch_size=args.batch_size, shuffle=True,
        num_workers=args.num_workers, pin_memory=True, drop_last=True,
    )
    val_loader = DataLoader(
        val_ds, batch_size=args.batch_size, shuffle=False,
        num_workers=args.num_workers, pin_memory=True,
    )

    # Model
    model = AngularFreqNetV2().to(device)
    params = sum(p.numel() for p in model.parameters())
    logger.info(f"Model: AngularFreqNetV2, params={params:,}")

    optimizer = Adam(model.parameters(), lr=args.lr, weight_decay=args.weight_decay)
    scheduler = CosineAnnealingLR(optimizer, T_max=args.epochs, eta_min=1e-6)

    # Training loop
    best_overall_mae = float("inf")
    best_epoch = -1
    history = []

    for epoch in range(1, args.epochs + 1):
        logger.info(f"=== Epoch {epoch}/{args.epochs} ===")
        t0 = time.time()

        avg_loss = train_one_epoch(model, train_loader, optimizer, device, epoch)
        scheduler.step()

        elapsed = time.time() - t0
        logger.info(f"  Train loss={avg_loss:.6f} ({elapsed:.1f}s)")

        val_metrics = validate(model, val_loader, device)
        overall_mae = val_metrics["MAE_overall"]
        logger.info(f"  Val MAE_overall={overall_mae:.6f}")

        history.append({
            "epoch": epoch,
            "train_loss": avg_loss,
            "val_metrics": val_metrics,
        })

        # Save best
        if overall_mae < best_overall_mae:
            best_overall_mae = overall_mae
            best_epoch = epoch
            torch.save({
                "epoch": epoch,
                "model_state_dict": model.state_dict(),
                "optimizer_state_dict": optimizer.state_dict(),
                "val_metrics": val_metrics,
                "overall_mae": overall_mae,
            }, os.path.join(args.output_dir, "best_model.pth"))
            logger.info(f"  * New best overall MAE={overall_mae:.6f}")

    # Final report
    logger.info("=" * 60)
    logger.info("TRAINING COMPLETE")
    logger.info(f"  Best val MAE: {best_overall_mae:.6f} at epoch {best_epoch}")
    if history:
        last = history[-1]["val_metrics"]
        for k in sorted(last.keys()):
            if k.startswith("MAE_"):
                logger.info(f"  {k} (last epoch): {last[k]:.6f}")

    # Save final checkpoint
    torch.save({
        "epoch": args.epochs,
        "model_state_dict": model.state_dict(),
        "history": history,
        "best_overall_mae": best_overall_mae,
        "best_epoch": best_epoch,
    }, os.path.join(args.output_dir, "final_model.pth"))

    with open(os.path.join(args.output_dir, "training_history.json"), "w") as f:
        json.dump({
            "config": vars(args),
            "total_params": params,
            "best_overall_mae": best_overall_mae,
            "best_epoch": best_epoch,
            "epochs": history,
        }, f, indent=2)

    logger.info(f"Training complete. Output: {args.output_dir}")


if __name__ == "__main__":
    main()


