"""Analyze domain distribution in the training dataset.

Counts scenes per domain (Lambertian / Non-Lambertian / Urban)
using the project's ManifestParser, which reads DATASET_MANIFEST.json.
"""

import json
import os
import sys
from collections import Counter

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from datasets.unified_lf_dataset import load_manifest, GROUP_MAP


def main():
    mp = load_manifest("DATASET_MANIFEST.json")

    # Count per dataset and per domain, split by train/val
    train_counter = Counter()
    val_counter = Counter()
    per_dataset_train = Counter()
    per_dataset_val = Counter()

    for s in mp.scenes:
        group = s["group"]
        dataset = s["dataset"]
        split = s["split"]

        if split == "train":
            train_counter[group] += 1
            per_dataset_train[f"{dataset} ({group})"] += 1
        else:
            val_counter[group] += 1
            per_dataset_val[f"{dataset} ({group})"] += 1

    print("=" * 60)
    print("DOMAIN DISTRIBUTION ANALYSIS")
    print("=" * 60)

    print("\n--- Per-Dataset Breakdown (TRAIN) ---")
    for k, v in sorted(per_dataset_train.items()):
        print(f"  {k}: {v} scenes")

    print("\n--- Per-Domain Summary (TRAIN) ---")
    total_train = sum(train_counter.values())
    for group in ["Lambertian", "Non-Lambertian", "Urban"]:
        count = train_counter.get(group, 0)
        pct = 100.0 * count / max(total_train, 1)
        print(f"  {group}: {count} scenes ({pct:.1f}%)")
    print(f"  TOTAL: {total_train} scenes")

    print("\n--- Per-Dataset Breakdown (VAL) ---")
    for k, v in sorted(per_dataset_val.items()):
        print(f"  {k}: {v} scenes")

    print("\n--- Per-Domain Summary (VAL) ---")
    total_val = sum(val_counter.values())
    for group in ["Lambertian", "Non-Lambertian", "Urban"]:
        count = val_counter.get(group, 0)
        pct = 100.0 * count / max(total_val, 1)
        print(f"  {group}: {count} scenes ({pct:.1f}%)")
    print(f"  TOTAL: {total_val} scenes")

    # Imbalance ratio
    if train_counter:
        max_count = max(train_counter.values())
        min_count = min(train_counter.values())
        print(f"\n--- Imbalance Ratio ---")
        print(f"  Max/Min domain ratio: {max_count/min_count:.1f}x")
        print(f"  ({max(train_counter, key=train_counter.get)}={max_count} vs "
              f"{min(train_counter, key=train_counter.get)}={min_count})")

    # Recommended sampling weights
    print("\n--- Recommended Sampling Weights (inverse domain frequency) ---")
    for group in ["Lambertian", "Non-Lambertian", "Urban"]:
        count = train_counter.get(group, 0)
        weight = 1.0 / max(count, 1)
        print(f"  {group}: weight = 1/{count} = {weight:.6f}")


if __name__ == "__main__":
    main()


