"""
Dry run: Load 1 real batch, forward pass, compute loss, print it.
Verifies the complete pipeline: dataset -> model -> loss.
Uses ONLY real data from the project's dataset loader.
"""
import os
import sys
import torch
import torch.nn.functional as F

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from datasets.unified_lf_dataset import UnifiedLFDataset
from models.angular_freq_depth_net_v2 import AngularFreqDepthNetV2


def main():
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    print(f"Device: {device}")

    # Load real data
    print("Loading dataset...")
    ds = UnifiedLFDataset(
        manifest_path="DATASET_MANIFEST.json",
        split="train",
        target_size=(256, 256),
        num_views=81,
    )
    print(f"Dataset: {len(ds)} scenes")

    # Load first sample
    sample = ds[0]
    views = sample["views"].unsqueeze(0).to(device)  # (1, V, C, H, W)
    gt = sample["gt"].unsqueeze(0).to(device)          # (1, 1, H, W)
    print(f"views: {views.shape}, range=[{views.min():.3f}, {views.max():.3f}]")
    print(f"gt:    {gt.shape}, range=[{gt.min():.3f}, {gt.max():.3f}]")
    assert views.shape == (1, 81, 3, 256, 256), f"Unexpected views shape: {views.shape}"
    assert gt.shape == (1, 1, 256, 256), f"Unexpected gt shape: {gt.shape}"

    # Load model
    print("Creating model...")
    model = AngularFreqDepthNetV2().to(device)
    n_params = sum(p.numel() for p in model.parameters())
    print(f"Model params: {n_params:,}")

    # Forward pass
    print("Running forward pass...")
    model.train()
    pred = model(views)
    print(f"pred: {pred.shape}, range=[{pred.min():.3f}, {pred.max():.3f}]")
    assert pred.shape == gt.shape, f"Shape mismatch: pred={pred.shape}, gt={gt.shape}"

    # Compute loss
    loss = F.l1_loss(pred, gt)
    print(f"\nDRY RUN: loss = {loss.item():.6f}")

    # Verify loss is valid
    assert torch.isfinite(loss), f"Loss is not finite: {loss.item()}"
    assert loss.item() > 0, f"Loss is zero or negative: {loss.item()}"

    # Backward pass (verify gradients flow)
    loss.backward()
    grad_norms = []
    for name, p in model.named_parameters():
        if p.grad is not None:
            grad_norms.append((name, p.grad.norm().item()))

    if grad_norms:
        max_grad = max(g for _, g in grad_norms)
        min_grad = min(g for _, g in grad_norms)
        print(f"Gradient stats: {len(grad_norms)} params with gradients")
        print(f"  Max grad norm: {max_grad:.6f}")
        print(f"  Min grad norm: {min_grad:.6f}")
    else:
        print("WARNING: No gradients computed!")

    print("\nSUCCESS: Forward pass + loss + backward pass all work with real data!")


if __name__ == "__main__":
    main()


