"""
综合验证实验：测试所有方法在多个场景上的泛化能力

方向4：验证实验
- 测试自适应特征选择在更多场景上的表现
- 测试特征融合的泛化能力
- 对比所有方法的优劣

混合方案探索：
- 自适应选择 + 乘法融合
- 基于场景类型的动态策略

分析BRDF粗糙度失败原因：
- 9x9角域分辨率限制
- 角度采样不足
"""
import numpy as np
from PIL import Image
from pathlib import Path
import matplotlib
matplotlib.use("Agg")
import matplotlib.pyplot as plt
from matplotlib.gridspec import GridSpec
from scipy.stats import entropy as scipy_entropy, kurtosis
from scipy.optimize import curve_fit
import json

OUT = Path("/home/bigboss/code/depth_estimation_unify_theory/outputs/energy_maps")
OUT.mkdir(parents=True, exist_ok=True)

A = 9

# ============================================================================
# 核心函数
# ============================================================================

def load_scene(scene_dir, spatial_size=256):
    views = []
    for i in range(81):
        img = np.array(Image.open(str(scene_dir / f"input_Cam{i:03d}.png"))).astype(np.float32) / 255.0
        g = 0.299*img[:,:,0] + 0.587*img[:,:,1] + 0.114*img[:,:,2]
        views.append(np.array(Image.fromarray(g).resize((spatial_size, spatial_size), Image.BILINEAR)))
    return np.array(views).reshape(A, A, spatial_size, spatial_size)

def compute_angular_entropy(patch_flat, range_max=1.0):
    hist, _ = np.histogram(patch_flat, bins=20, range=(0.0, range_max))
    prob = hist / (hist.sum() + 1e-12)
    return scipy_entropy(prob + 1e-12)

def compute_angular_kurtosis(patch_flat):
    std = patch_flat.std()
    if std < 1e-6:
        return 0.0
    try:
        return kurtosis(patch_flat)
    except:
        return 0.0

def compute_freq_ratio(patch):
    fft_patch = np.fft.fft2(patch)
    fft_mag = np.abs(fft_patch)
    low_freq = fft_mag[0:3, 0:3].sum()
    high_freq = fft_mag.sum() - low_freq
    if low_freq > 1e-6:
        return high_freq / low_freq
    return 0.0

def normalize_map(feat_map):
    min_val = feat_map.min()
    max_val = feat_map.max()
    if max_val - min_val < 1e-12:
        return feat_map * 0
    return (feat_map - min_val) / (max_val - min_val)

def compute_region_ratio(feat_map, scene_name):
    """计算区域比值"""
    if "David" in scene_name:
        r1 = feat_map[80:180, 80:180].mean()
        r2 = np.concatenate([feat_map[:60,:60].flatten(), feat_map[:60,196:].flatten(),
                              feat_map[196:,:60].flatten(), feat_map[196:,196:].flatten()]).mean()
    else:
        r1 = feat_map[:128].mean()
        r2 = feat_map[128:].mean()
    return r1, r2, r1 / (r2 + 1e-12)

# ============================================================================
# 方法1：自适应特征选择
# ============================================================================

def adaptive_feature_selection(ang, spatial_size=256):
    """自适应选择 Kurtosis 或 Norm Entropy"""
    # 计算归一化 Kurtosis
    norm_kurt_map = np.zeros((spatial_size, spatial_size))
    for h in range(spatial_size):
        for w in range(spatial_size):
            patch = ang[:, :, h, w]
            mean_val = patch.mean()
            if mean_val < 1e-6:
                continue
            patch_norm = patch / mean_val
            norm_kurt_map[h, w] = compute_angular_kurtosis(patch_norm.ravel())

    norm_kurt_std = norm_kurt_map.std()

    if norm_kurt_std > 1.2:
        feature_type = "kurtosis"
        feat_map = np.zeros((spatial_size, spatial_size))
        for h in range(spatial_size):
            for w in range(spatial_size):
                patch = ang[:, :, h, w].ravel()
                feat_map[h, w] = compute_angular_kurtosis(patch)
    else:
        feature_type = "norm_entropy"
        feat_map = np.zeros((spatial_size, spatial_size))
        for h in range(spatial_size):
            for w in range(spatial_size):
                patch = ang[:, :, h, w]
                mean_val = patch.mean()
                if mean_val < 1e-6:
                    continue
                patch_norm = patch / mean_val
                feat_map[h, w] = compute_angular_entropy(patch_norm.ravel(), range_max=3.0)

    return feat_map, feature_type, norm_kurt_std

# ============================================================================
# 方法2：特征融合
# ============================================================================

def compute_features_for_fusion(ang, spatial_size=256):
    """计算 Norm Entropy 和 Freq Ratio"""
    norm_ent = np.zeros((spatial_size, spatial_size))
    freq_ratio = np.zeros((spatial_size, spatial_size))

    for h in range(spatial_size):
        for w in range(spatial_size):
            patch = ang[:, :, h, w]

            mean_val = patch.mean()
            if mean_val > 1e-6:
                patch_norm = patch / mean_val
                norm_ent[h, w] = compute_angular_entropy(patch_norm.ravel(), range_max=3.0)

            freq_ratio[h, w] = compute_freq_ratio(patch)

    return norm_ent, freq_ratio

def multiplicative_fusion(norm_ent, freq_ratio):
    norm_ent_norm = normalize_map(norm_ent)
    freq_ratio_norm = normalize_map(freq_ratio)
    return norm_ent_norm * freq_ratio_norm

# ============================================================================
# 方法3：BRDF建模（简化版，用于分析）
# ============================================================================

def beckmann_distribution(theta, m):
    tan_theta = np.tan(theta)
    cos_theta = np.cos(theta)
    return np.exp(-tan_theta**2 / m**2) / (np.pi * m**2 * cos_theta**4 + 1e-12)

def simplified_brdf_model(theta, rho_d, rho_s, m):
    return rho_d + rho_s * beckmann_distribution(theta, m)

def fit_brdf_to_patch(patch):
    patch_flat = patch.ravel()
    n = len(patch_flat)

    center = 4
    angles = np.zeros(n)
    idx = 0
    for u in range(9):
        for v in range(9):
            dist = np.sqrt((u - center)**2 + (v - center)**2)
            angles[idx] = dist * (np.pi / 4) / (4 * np.sqrt(2))
            idx += 1

    try:
        popt, _ = curve_fit(
            simplified_brdf_model,
            angles,
            patch_flat,
            p0=[patch_flat.mean(), 0.1, 0.5],
            bounds=([0, 0, 0.01], [1, 1, 2.0]),
            maxfev=5000
        )
        return popt
    except:
        return patch_flat.mean(), 0.0, 1.0

# ============================================================================
# 方法4：混合方案（自适应选择 + 乘法融合）
# ============================================================================

def hybrid_method(ang, spatial_size=256):
    """
    混合方案：
    1. 先用自适应选择判断场景类型
    2. 如果是 Kurtosis 类型 → 用 Kurtosis
    3. 如果是 Norm Entropy 类型 → 用乘法融合 (Norm Entropy × Freq Ratio)
    """
    # 先计算归一化 Kurtosis std 来判断场景类型
    norm_kurt_map = np.zeros((spatial_size, spatial_size))
    for h in range(spatial_size):
        for w in range(spatial_size):
            patch = ang[:, :, h, w]
            mean_val = patch.mean()
            if mean_val < 1e-6:
                continue
            patch_norm = patch / mean_val
            norm_kurt_map[h, w] = compute_angular_kurtosis(patch_norm.ravel())

    norm_kurt_std = norm_kurt_map.std()

    if norm_kurt_std > 1.2:
        # David 类型：用 Kurtosis
        method_name = "kurtosis_only"
        feat_map = np.zeros((spatial_size, spatial_size))
        for h in range(spatial_size):
            for w in range(spatial_size):
                patch = ang[:, :, h, w].ravel()
                feat_map[h, w] = compute_angular_kurtosis(patch)
    else:
        # Apple 类型：用乘法融合
        method_name = "multiplicative_fusion"
        norm_ent, freq_ratio = compute_features_for_fusion(ang, spatial_size)
        feat_map = multiplicative_fusion(norm_ent, freq_ratio)

    return feat_map, method_name, norm_kurt_std

# ============================================================================
# 主实验流程
# ============================================================================

BASE_NL = Path("/home/bigboss/code/depth_estimation_unify_theory/data/Non-lambertian_dataset_zhenglong")
SPATIAL_SIZE = 256

print("Loading scenes...")
scenes = {
    "David 50%": load_scene(BASE_NL / "David 50%", spatial_size=SPATIAL_SIZE),
    "Apple 20%": load_scene(BASE_NL / "Apple 20%", spatial_size=SPATIAL_SIZE),
    "Apple 50%": load_scene(BASE_NL / "Apple 50%", spatial_size=SPATIAL_SIZE),
    "Apple 90%": load_scene(BASE_NL / "Apple 90%", spatial_size=SPATIAL_SIZE),
}

print("\n" + "="*100)
print("综合验证实验")
print("="*100)

all_results = {}

for name, ang in scenes.items():
    print(f"\n{'='*80}")
    print(f"场景: {name}")
    print(f"{'='*80}")

    results = {}

    # 方法1：自适应特征选择
    print("\n[方法1] 自适应特征选择...")
    feat1, type1, std1 = adaptive_feature_selection(ang, spatial_size=SPATIAL_SIZE)
    r1_1, r1_2, ratio1 = compute_region_ratio(feat1, name)
    results["adaptive"] = {
        "feat_map": feat1,
        "type": type1,
        "norm_kurt_std": std1,
        "r1": r1_1,
        "r2": r1_2,
        "ratio": ratio1,
    }
    print(f"  选择: {type1}, norm_kurt_std={std1:.2f}, Ratio={ratio1:.2f}")

    # 方法2：特征融合（乘法）
    print("\n[方法2] 乘法融合...")
    norm_ent, freq_ratio = compute_features_for_fusion(ang, spatial_size=SPATIAL_SIZE)
    feat2 = multiplicative_fusion(norm_ent, freq_ratio)
    r2_1, r2_2, ratio2 = compute_region_ratio(feat2, name)
    results["multiplicative"] = {
        "feat_map": feat2,
        "r1": r2_1,
        "r2": r2_2,
        "ratio": ratio2,
        "norm_ent": norm_ent,
        "freq_ratio": freq_ratio,
    }
    print(f"  Ratio={ratio2:.2f}")

    # 方法3：BRDF ρ_s（只计算部分像素用于分析）
    print("\n[方法3] BRDF ρ_s（采样分析）...")
    # 为了节省时间，只采样 64x64 像素
    sample_size = 64
    step = SPATIAL_SIZE // sample_size
    rho_s_map = np.zeros((sample_size, sample_size))
    for i in range(sample_size):
        for j in range(sample_size):
            h, w = i * step, j * step
            patch = ang[:, :, h, w]
            _, rho_s, _ = fit_brdf_to_patch(patch)
            rho_s_map[i, j] = rho_s
    # 上采样回原尺寸
    from scipy.ndimage import zoom
    rho_s_full = zoom(rho_s_map, SPATIAL_SIZE / sample_size, order=1)
    r3_1, r3_2, ratio3 = compute_region_ratio(rho_s_full, name)
    results["brdf_rho_s"] = {
        "feat_map": rho_s_full,
        "r1": r3_1,
        "r2": r3_2,
        "ratio": ratio3,
    }
    print(f"  Ratio={ratio3:.2f}")

    # 方法4：混合方案
    print("\n[方法4] 混合方案（自适应+融合）...")
    feat4, method4, std4 = hybrid_method(ang, spatial_size=SPATIAL_SIZE)
    r4_1, r4_2, ratio4 = compute_region_ratio(feat4, name)
    results["hybrid"] = {
        "feat_map": feat4,
        "method": method4,
        "norm_kurt_std": std4,
        "r1": r4_1,
        "r2": r4_2,
        "ratio": ratio4,
    }
    print(f"  方法: {method4}, norm_kurt_std={std4:.2f}, Ratio={ratio4:.2f}")

    all_results[name] = results

# ============================================================================
# 生成综合报告
# ============================================================================

print("\n" + "="*100)
print("综合报告")
print("="*100)

methods = ["adaptive", "multiplicative", "brdf_rho_s", "hybrid"]
method_names = {
    "adaptive": "自适应选择",
    "multiplicative": "乘法融合",
    "brdf_rho_s": "BRDF ρ_s",
