}

print(f"\n{'场景':<15} {'方法':<15} {'Region1':<10} {'Region2':<10} {'Ratio':<10}")
print("-" * 70)

for name in scenes.keys():
    for method in methods:
        r = all_results[name][method]
        print(f"{name:<15} {method_names[method]:<15} {r['r1']:<10.4f} {r['r2']:<10.4f} {r['ratio']:<10.2f}")

# ============================================================================
# 可视化：综合对比图
# ============================================================================

print("\n生成综合对比图...")

fig = plt.figure(figsize=(24, 16))
gs = GridSpec(4, 5, figure=fig, hspace=0.5, wspace=0.3)
fig.suptitle("综合验证实验：4种方法在多个场景上的对比\n"
             "自适应选择 | 乘法融合 | BRDF ρ_s | 混合方案",
             fontsize=16, fontweight="bold", y=0.995)

scene_names = list(scenes.keys())

for idx, name in enumerate(scene_names):
    row = idx

    # 中心视图
    ax = fig.add_subplot(gs[row, 0])
    ax.imshow(scenes[name][4, 4], cmap="gray")
    if "Apple" in name:
        ax.axhline(y=128, color="red", linewidth=2, linestyle="--")
    ax.set_title(f"{name}\nCenter View", fontsize=10, fontweight="bold")
    ax.axis("off")

    # 4种方法
    for col, method in enumerate(methods):
        ax = fig.add_subplot(gs[row, col+1])
        r = all_results[name][method]
        feat_map = r["feat_map"]

        im = ax.imshow(feat_map, cmap="viridis")
        if "Apple" in name:
            ax.axhline(y=128, color="white", linewidth=2, linestyle="--")

        ratio = r["ratio"]
        title = f"{method_names[method]}\nRatio={ratio:.2f}"
        if method == "adaptive":
            title += f"\n({r['type']})"
        elif method == "hybrid":
