        ax.set_title(title, fontsize=9)
        ax.axis("off")
        plt.colorbar(im, ax=ax, fraction=0.046)

fig.savefig(str(OUT / "comprehensive_validation.png"), dpi=200, bbox_inches="tight")
plt.close(fig)
print(f"Saved: {OUT / 'comprehensive_validation.png'}")

# ============================================================================
# 生成详细分析报告（JSON）
# ============================================================================

report = {
    "experiment": "综合验证实验",
    "scenes": list(scenes.keys()),
    "methods": {
        "adaptive": {
            "name": "自适应特征选择",
            "description": "根据 norm_kurt_std 自动选择 Kurtosis 或 Norm Entropy",
            "threshold": 1.2,
